#include<bits/stdc++.h>
using namespace std;
int a[100001],b[100001],n,cnt=1,ans=0;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i];
    for(int i=1;i<=n;i++) cin>>b[i];
    sort(a+1,a+1+n);
    sort(b+1,b+1+n);
    for(int i=1;i<=n;i++) if(a[i]>b[cnt]) cnt++,ans++;
    cout<<ans;
    return 0;
}
